{"credits": [{"type": "analyst", "user": {"avatar_url": "https://avatars.githubusercontent.com/u/95610011?v=4", "events_url": "https://api.github.com/users/kmagdziarz/events{/privacy}", "followers_url": "https://api.github.com/users/kmagdziarz/followers", "following_url": "https://api.github.com/users/kmagdziarz/following{/other_user}", "gists_url": "https://api.github.com/users/kmagdziarz/gists{/gist_id}", "gravatar_id": "", "html_url": "https://github.com/kmagdziarz", "id": 95610011, "login": "kmagdziarz", "node_id": "U_kgDOBbLkmw", "organizations_url": "https://api.github.com/users/kmagdziarz/orgs", "received_events_url": "https://api.github.com/users/kmagdziarz/received_events", "repos_url": "https://api.github.com/users/kmagdziarz/repos", "site_admin": false, "starred_url": "https://api.github.com/users/kmagdziarz/starred{/owner}{/repo}", "subscriptions_url": "https://api.github.com/users/kmagdziarz/subscriptions", "type": "User", "url": "https://api.github.com/users/kmagdziarz", "user_view_type": "public"}}], "cve_id": "CVE-2026-40453", "cvss": {"score": 9.9, "vector_string": "CVSS:3.1/AV:N/AC:L/PR:L/UI:N/S:C/C:H/I:H/A:H"}, "cvss_severities": {"cvss_v3": {"score": 9.9, "vector_string": "CVSS:3.1/AV:N/AC:L/PR:L/UI:N/S:C/C:H/I:H/A:H"}, "cvss_v4": {"score": 0.0, "vector_string": null}}, "cwes": [{"cwe_id": "CWE-178", "name": "Improper Handling of Case Sensitivity"}], "description": "The fix for CVE-2025-27636 added setLowerCase(true) to HttpHeaderFilterStrategy so that case-variant header names such as 'CAmelExecCommandExecutable' are filtered out alongside 'CamelExecCommandExecutable'. The same setLowerCase(true) call was not applied to five non-HTTP HeaderFilterStrategy implementations: JmsHeaderFilterStrategy and ClassicJmsHeaderFilterStrategy in camel-jms, SjmsHeaderFilterStrategy in camel-sjms, CoAPHeaderFilterStrategy in camel-coap, and GooglePubsubHeaderFilterStrategy in camel-google-pubsub. Because those strategies use case-sensitive String.startsWith('Camel'/'camel') filtering while the Camel Exchange stores headers in a case-insensitive map, an attacker with JMS (or equivalent) producer access to the broker consumed by a Camel route can inject case-variant Camel internal headers, which are then resolved by downstream components such as camel-exec and camel-file using their canonical casing. This enables remote code execution and arbitrary file write on routes that forward JMS messages to header-driven components.

This issue affects Apache Camel: from 3.0.0 before 4.14.6, from 4.15.0 before 4.18.2, from 4.19.0 before 4.20.0.

Users are recommended to upgrade to version 4.20.0, which fixes the issue. If users are on the 4.14.x LTS releases stream, then they are suggested to upgrade to 4.14.6. If users are on the 4.18.x releases stream, then they are suggested to upgrade to 4.18.2.", "epss": {"percentage": 0.0086, "percentile": 0.5393}, "ghsa_id": "GHSA-jg2m-9x48-3gvj", "github_reviewed_at": "2026-05-22T13:10:44Z", "html_url": "https://github.com/advisories/GHSA-jg2m-9x48-3gvj", "identifiers": [{"type": "GHSA", "value": "GHSA-jg2m-9x48-3gvj"}, {"type": "CVE", "value": "CVE-2026-40453"}], "nvd_published_at": "2026-04-27T09:16:01Z", "published_at": "2026-04-27T09:34:39Z", "references": ["https://nvd.nist.gov/vuln/detail/CVE-2026-40453", "https://camel.apache.org/security/CVE-2026-40453.html", "https://github.com/apache/camel/pull/22569", "https://github.com/apache/camel/pull/22575", "https://github.com/apache/camel/pull/22576", "https://github.com/apache/camel/commit/1e331daa4eea0a3f01d951e74cda8faee79495a2", "https://github.com/apache/camel/commit/301bb7401cd480895b94a28a8ad6cf04952d8125", "https://github.com/apache/camel/commit/3d2efeed2f6ea757f0254a1d1cdeb9a4f28ca147", "https://issues.apache.org/jira/browse/CAMEL-23313", "https://github.com/advisories/GHSA-jg2m-9x48-3gvj"], "repository_advisory_url": null, "severity": "critical", "source_code_location": "https://github.com/apache/camel", "summary": "Apache Camel has an incomplete fix for CVE-2025-27636", "type": "reviewed", "updated_at": "2026-05-22T13:10:46Z", "url": "https://api.github.com/advisories/GHSA-jg2m-9x48-3gvj", "vulnerabilities": [{"first_patched_version": "4.14.6", "package": {"ecosystem": "maven", "name": "org.apache.camel:camel-coap"}, "vulnerable_functions": [], "vulnerable_version_range": ">= 3.0.0, < 4.14.6"}, {"first_patched_version": "4.18.2", "package": {"ecosystem": "maven", "name": "org.apache.camel:camel-coap"}, "vulnerable_functions": [], "vulnerable_version_range": ">= 4.15.0, < 4.18.2"}, {"first_patched_version